+  // Stats
+  private totalEmbeddings: number = 0;
+  private totalLatencyMs: number = 0;
+  private cacheHits: number = 0;
+
+  // Cache (in-memory LRU)
+  private cache: LRUCache;
+  private cacheEnabled: boolean;
