+      persistentCacheStats = {
+        enabled: true,
+        entries: cacheStats.totalEntries,
+        hits: cacheStats.hits,
+        misses: cacheStats.misses,
+        hitRate: cacheStats.hitRate,
+        dbSizeKB: Math.round(cacheStats.dbSizeBytes / 1024),
