+      trajectories: {
+        total: stats.totalTrajectories,
+        active: activeCount,
+        successful: stats.successfulTrajectories,
+      },
+      routings: {
+        total: stats.totalRoutings,
+        accuracy: stats.totalRoutings > 0
+          ? stats.successfulRoutings / stats.totalRoutings
