+    PostToolUse: [{ hooks: [postToolUseHook] }],
+    PostToolUseFailure: [{ hooks: [postToolUseFailureHook] }],
+    SessionStart: [{ hooks: [sessionStartHook] }],
+    SessionEnd: [{ hooks: [sessionEndHook] }],
